section.code:
{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "type": "object",
  "title": "agent-failure-taxonomy-output",
  "required": [
    "labels",
    "primary_label_per_instance",
    "history_log",
    "owner",
    "version",
    "forbidden_seen"
  ],
  "properties": {
    "labels": {
      "description": "{name, definition, remediation_lane, detector}."
    },
    "primary_label_per_instance": {
      "description": "Always true."
    },
    "history_log": {
      "description": "{instance_id, old_label, new_label, timestamp, rationale}."
    },
    "owner": {
      "description": "Taxonomy owner."
    },
    "version": {
      "description": "Semver."
    },
    "forbidden_seen": {
      "description": "Forbidden patterns matched (must be empty)."
    }
  }
}
